from collections import defaultdict

class Solution:
    def longestSubarray(self, nums, k):
        freq = defaultdict(int)
        left = 0
        repeated = 0
        ans = 0

        for right in range(len(nums)):
            freq[nums[right]] += 1

            if freq[nums[right]] == 2:
                repeated += 1

            while repeated > k:
                freq[nums[left]] -= 1
                if freq[nums[left]] == 1:
                    repeated -= 1
                left += 1

            ans = max(ans, right - left + 1)

        return ans

