class Solution:
    def minCost(self, grid):
        m, n = len(grid), len(grid[0])
        dist = [[float('inf')] * n for _ in range(m)]
        pq = [(0, 0, 0)]
        dist[0][0] = 0

        dirs = [(0,1),(0,-1),(1,0),(-1,0)]

        while pq:
            cost, x, y = heappop(pq)
            if (x, y) == (m-1, n-1):
                return cost

            for i, (dx, dy) in enumerate(dirs):
                nx, ny = x + dx, y + dy
                if 0 <= nx < m and 0 <= ny < n:
                    ncost = cost + (grid[x][y] != i + 1)
                    if ncost < dist[nx][ny]:
                        dist[nx][ny] = ncost
                        heappush(pq, (ncost, nx, ny))

        return -1

