class Solution:
    def minimumMoves(self, grid):
        n = len(grid)
        q = deque([(0, 0, 0, 0)])
        vis = set([(0,0,0)])

        while q:
            x, y, d, steps = q.popleft()
            if x == n-1 and y == n-2 and d == 0:
                return steps

            if d == 0:
                if y+2 < n and grid[x][y+2] == 0 and (x,y+1,0) not in vis:
                    vis.add((x,y+1,0))
                    q.append((x,y+1,0,steps+1))

                if x+1 < n and grid[x+1][y] == 0 and grid[x+1][y+1] == 0:
                    if (x+1,y,0) not in vis:
                        vis.add((x+1,y,0))
                        q.append((x+1,y,0,steps+1))
                    if (x,y,1) not in vis:
                        vis.add((x,y,1))
                        q.append((x,y,1,steps+1))
            else:
                if x+2 < n and grid[x+2][y] == 0 and (x+1,y,1) not in vis:
                    vis.add((x+1,y,1))
                    q.append((x+1,y,1,steps+1))

                if y+1 < n and grid[x][y+1] == 0 and grid[x+1][y+1] == 0:
                    if (x,y+1,1) not in vis:
                        vis.add((x,y+1,1))
                        q.append((x,y+1,1,steps+1))
                    if (x,y,0) not in vis:
                        vis.add((x,y,0))
                        q.append((x,y,0,steps+1))

        return -1

