class Solution:
    def longestPalindrome(self, n, edges, labels):
        g = [[] for _ in range(n)]

        for u, v in edges:
            g[u].append(v)
            g[v].append(u)

        @lru_cache(None)
        def dfs(u, v):
            ans = 0
            if labels[u] == labels[v]:
                ans = 2 if u != v else 1
                for nu in g[u]:
                    for nv in g[v]:
                        ans = max(ans, 2 + dfs(nu, nv))
            return ans

        res = 1
        for i in range(n):
            for j in range(n):
                res = max(res, dfs(i, j))

        return res

