class Solution:
    def shortestPath(self, n, edges, src):
        g = defaultdict(list)

        for u, v, w in edges:
            g[u].append((v, w))

        dist = [float('inf')] * n
        dist[src] = 0
        pq = [(0, src)]

        while pq:
            d, u = heappop(pq)
            if d > dist[u]:
                continue

            for v, w in g[u]:
                nd = d + w
                if nd < dist[v]:
                    dist[v] = nd
                    heappush(pq, (nd, v))

        return dist

class Solution:
    def convert(self, n):
        digits = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ'

        def base(x, b):
            if x == 0:
                return '0'
            res = ''
