class Solution:
    def minSwaps(self, nums):
        even = [i for i,x in enumerate(nums) if x%2==0]
        odd = [i for i,x in enumerate(nums) if x%2]

        if abs(len(even)-len(odd)) > 1:
            return -1

        def solve(start_even):
            pos = even if start_even else odd
            ans = 0
            for i,p in enumerate(pos):
                ans += abs(p - 2*i)
            return ans

        res = float('inf')
        if len(even) >= len(odd):
            res = min(res, solve(True))
        if len(odd) >= len(even):
            res = min(res, solve(False))

        return res

