class Solution:
    def findMedian(self, n, edges, weight):
        g = defaultdict(list)

        for u, v in edges:
            g[u].append(v)
            g[v].append(u)

        total = sum(weight)
        ans = 0

        def dfs(u, p):
            nonlocal ans
            s = weight[u]

            for v in g[u]:
                if v != p:
                    s += dfs(v, u)

            if s * 2 >= total:
                ans = u

            return s

        dfs(0, -1)
        return ans

