        total = 1 << n
        ans = 0

        for mask in range(1, total - 1):
            xor_val = 0
            and_val = -1

            for i in range(n):
                if mask & (1 << i):
                    xor_val ^= nums[i]
                else:
                    if and_val == -1:
                        and_val = nums[i]
                    else:
                        and_val &= nums[i]

            ans = max(ans, xor_val + and_val)

        return ans

class Solution:
    def minAbsDiff(self, grid, k):
        n = len(grid)
        m = len(grid[0])
        ans = [[0] * (m - k + 1) for _ in range(n - k + 1)]

        for i in range(n - k + 1):
            for j in range(m - k + 1):
                arr = []

                for x in range(i, i + k):
                    for y in range(j, j + k):
                        arr.append(grid[x][y])

                arr.sort()
                best = float('inf')

                for p in range(1, len(arr)):
                    best = min(best, arr[p] - arr[p - 1])

                ans[i][j] = best

        return ans

class Solution:
    def maximizePrimes(self, nums):
        def is_prime(n):
            if n < 2:
                return False

            i = 2
            while i * i <= n:
                if n % i == 0:
                    return False
                i += 1

            return True

        left = set()
        right = set()

        for num in nums:
            if is_prime(num):
                right.add(num)

        ans = len(right)

        for num in nums:
            if is_prime(num):
                left.add(num)
                right.discard(num)

            ans = max(ans, len(left) + len(right))

        return ans

class Solution:
    def shortestSubarray(self, nums):
        n = len(nums)
        left = n
        right = 0

        for i in range(1, n):
            if nums[i] < nums[i - 1]:
                right = i

        for i in range(n - 2, -1, -1):
            if nums[i] > nums[i + 1]:
                left = i

        return right - left + 1 if right > left else 0

from collections import deque

class Solution:
    def minimumMoves(self, classroom):
        n = len(classroom)
        m = len(classroom[0])

        q = deque([(0, 0, 0)])
        visited = [[False] * m for _ in range(n)]
        visited[0][0] = True

        dirs = [(1,0),(-1,0),(0,1),(0,-1)]

        while q:
            x, y, dist = q.popleft()

            if x == n - 1 and y == m - 1:
                return dist

            for dx, dy in dirs:
                nx = x + dx
                ny = y + dy

                if 0 <= nx < n and 0 <= ny < m and not visited[nx][ny] and classroom[nx][ny] != '#':
                    visited[nx][ny] = True
                    q.append((nx, ny, dist + 1))

        return -1

