class Solution:
    def minDistance(self, word1, word2):
        n = len(word1)
        m = len(word2)

        dp = [[0] * (m + 1) for _ in range(n + 1)]

        for i in range(n + 1):
            dp[i][0] = i

        for j in range(m + 1):
            dp[0][j] = j

        for i in range(1, n + 1):
            for j in range(1, m + 1):
                if word1[i - 1] == word2[j - 1]:
                    dp[i][j] = dp[i - 1][j - 1]
                else:
                    dp[i][j] = 1 + min(dp[i - 1][j - 1], dp[i - 1][j], dp[i][j - 1])

        return dp[n][m]

class Solution:
    def maxProduct(self, n):
        first = 0
        second = 0

        while n > 0:
            digit = n % 10

            if digit > first:
                second = first
                first = digit
            elif digit > second:
                second = digit

            n //= 10

        return first * second

