class Solution:
    def maximumPath(self, n, edges, k):
        dp = [float('-inf')] * n
        dp[0] = 0

        for _ in range(k):
            nxt = dp[:]

            for u, v, w in edges:
                if dp[u] != float('-inf'):
                    nxt[v] = max(nxt[v], dp[u] + w)

            dp = nxt

        return max(dp)

class Solution:
    def minimumCost(self, n, edges):
        parent = list(range(n))

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(a, b):
            parent[find(a)] = find(b)

        edges.sort(key=lambda x: x[2])
        ans = 0

        for u, v, w in edges:
            if find(u) != find(v):
                union(u, v)
                ans += w

        return ans

