class Solution:
    def subtreeInversionSum(self, parent, values):
        tree = defaultdict(list)

        for i in range(1, len(parent)):
            tree[parent[i]].append(i)

        self.ans = 0

        def dfs(node):
            total = values[node]

            for child in tree[node]:
                total += dfs(child)

            self.ans += total
            return total

        dfs(0)
        return self.ans

