class Solution:
    def minSwaps(self, nums):
        def digit_sum(x):
            s = 0
            while x:
                s += x % 10
                x //= 10
            return s

        arr = sorted([(digit_sum(nums[i]), i) for i in range(len(nums))])
        visited = [False] * len(nums)
        swaps = 0

        for i in range(len(nums)):
            if visited[i] or arr[i][1] == i:
                continue

            cycle = 0
            j = i

            while not visited[j]:
                visited[j] = True
                j = arr[j][1]
                cycle += 1

            swaps += cycle - 1

        return swaps

